import json
import re

# Load UC patents
uc_data = locals()['var_functions.query_db:12']
with open(uc_data, 'r') as f:
    uc_patents = json.load(f)

# Extract UC publication numbers
uc_numbers = set()
for p in uc_patents:
    info = p['Patents_info']
    m = re.search(r'([A-Z]{2}-[A-Z0-9-]+)', info)
    if m:
        uc_numbers.add(m.group(1))

print('UC patents:', len(uc_numbers))

# Extract citation patterns
all_data = locals()['var_functions.query_db:32']
with open(all_data, 'r') as f:
    all_patents = json.load(f)

results = []
assignees = {}

for patent in all_patents[:50000]:
    citation = patent['citation']
    if not citation or citation == '[]':
        continue

    # Check for UC citation
    found = None
    for n in uc_numbers:
        if n in citation:
            found = n
            break
    if not found:
        continue

    # Get assignee
    info = patent['Patents_info']
    assignee = None
    parts = info.split()
    for i in range(min(8, len(parts))):
        phrase = ' '.join(parts[:i+1])
        if 'UNIV CALIFORNIA' not in phrase.upper():
            assignee = phrase
            break

    if assignee and 'UNIV' not in assignee.upper():
        # Get CPC
        cpc_codes = []
        cpc_str = patent['cpc']
        if cpc_str and cpc_str != '[]':
            try:
                for item in json.loads(cpc_str):
                    if 'code' in item:
                        cpc_codes.append(item['code'])
            except:
                pass

        cpc_codes = list(set(cpc_codes))

        results.append({
            'uc_cited': found,
            'assignee': assignee,
            'cpc': cpc_codes
        })

        if assignee not in assignees:
            assignees[assignee] = set()
        assignees[assignee].update(cpc_codes)

print('Citations found:', len(results))
print('Assignees:', len(assignees))

with open('/tmp/citations.json', 'w') as f:
    json.dump({
        'citations': results,
        'assignees': {k: list(v) for k, v in assignees.items()}
    }, f)

print('__RESULT__:')
print(json.dumps({
    'citations': len(results),
    'assignees': len(assignees)
}))

